var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Ugh?!","TWN":"唔？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"드디어 따라잡았군.","JPN":"やっと追いついたぜ。","ENG":"Finally, I got you.","TWN":"終於被我抓到了吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"짧은 도주극에 대한 감상 좀 들어볼까, 도둑 기사 아가씨?","JPN":"短い逃走劇の感想を聞かせてくれるかい、泥棒騎士のお嬢ちゃん？","ENG":"Now, let’s hear your excuses, thieving knight girl.","TWN":"這麼短的時間內就被抓到，有什麼感想嗎，小偷騎士？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"젠장, 조금만 천천히 가라니까! 그러다 또 낭패 보면 어쩌려고!","JPN":"おい、もう少しゆっくり行けよ！　無茶してまた逃げられたらどうすんだ！","ENG":"Hey, I told you to slow down! What if something unexpected happens again?","TWN":"該死的！就叫你走慢一點！萬一又搞砸的話怎麼辦！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"꾸물거리다 다시 놓치는 것보다는 낫지. 여기서 리액터를 회수한다.","JPN":"グズグズして逃がすよりマシだろ？　ここでリアクターを回収するぞ。","ENG":"It’s better than losing her trail. We will retrieve the reactor here and now.","TWN":"總比又被她逃掉的好吧！我要拿回反應爐！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"빌어먹을……. 군인들이란 하나같이 말이 안 통한다니까.","JPN":"くそ……軍人は本当に言葉が通じないな。","ENG":"Darn... You soldiers are all so thick-headed.","TWN":"有夠討厭的……軍人真的都很難溝通欸！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그나마 그쪽이 알려 준 발신기가 있어서 다행이었어.","JPN":"それにしても、教えてもらった発信機のおかげで助かった。","ENG":"We were lucky to have the transmitter in the machine, though.","TWN":"不過幸好你有告訴我們發射器的事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그거 아니었으면 이번 의뢰는 완전히 실패했을 거야.","JPN":"あれがなかったら今回の依頼は完全に失敗していただろう。","ENG":"If you didn’t tell us about it, we never would have found the reactor.","TWN":"否則這次的委託應該會失敗收場吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"별말씀을요. 그렇게 고마워하실 만큼 대단한 도움도 못 드렸는걸요.","JPN":"とんでもないです。お礼を言われるほどのことではありません。","ENG":"You’re welcome, but I don’t think I did much to help.","TWN":"不用客氣，我沒做什麼啦。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그렇게까지 자기 비하할 것 없어.","JPN":"そんなに自分を卑下する必要はないさ。","ENG":"Stop abasing yourself.","TWN":"你不用這麼謙卑！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나도 여러모로 심경이 복잡하긴 하지만……. 도움이 된 건 분명한 사실이야.","JPN":"まあ俺も複雑な心境だが……役に立ったのは事実だ。","ENG":"You know, it’s a bit confusing for me to say this too... But, you really did help us.","TWN":"雖然我的心情也有點複雜……不過你有幫上忙是事實！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"감사…… 합니다.","JPN":"ありがとう……ございます。","ENG":"Thank you...","TWN":"謝……謝你。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨?!","JPN":"おじさん！？","ENG":"Mr. Mason?!","TWN":"大叔？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"음? 이 목소리는?","JPN":"うん？　この声は？","ENG":"Hmm? This voice?","TWN":"嗯？這個聲音是？ "},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오랜만입니다, 메이슨 씨.","JPN":"お久しぶりです、メイソンさん。","ENG":"Hello, Mr. Mason.","TWN":"梅森，好久不見。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"코핀 컴퍼니 친구들이잖아. 이런 데서 다 만나는군.","JPN":"コフィンカンパニーのお仲間じゃないか。こんなところで会うとはな。","ENG":"My dear friends from the Coffin Company. I didn’t expect to see you here.","TWN":"這不是科芬公司的人嗎！沒想到會在這裡見到你們。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"설마 작전 중이었던 건가?","JPN":"もしかして作戦中だったのか？","ENG":"Are you on a mission?","TWN":"你們該不會是正在作戰吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 응. 의뢰를 받아서 움직이던 도중에 의뢰인에게 습격 받았어.","JPN":"あ、うん。依頼された仕事を遂行していたら、依頼主に襲われたの。","ENG":"Oh, yeah. But then our client attacked us.","TWN":"喔，對啊，我們在執行委託的過程中，突然受到委託人的攻擊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"의뢰인이라고? 설마 저 꼬마 아가씨 말인가?","JPN":"依頼主……？　まさかあの嬢ちゃんのことか？","ENG":"Your client? That girl?","TWN":"委託人？該不會是那個小丫頭吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇습니다. 의뢰주와 고용인과의 신뢰관계가 이렇게 무너지다니 참 가슴 아픈 현실이죠.","JPN":"そうです。\\n依頼主と雇用人との信頼関係がこのように崩れてしまうとは悲しいですね。","ENG":"Yes. Such a tragedy, we can’t even trust our own clients anymore. What is the world coming to?","TWN":"是的，沒想到委託人和受僱人彼此間的信任，就這麼瓦解了，現實真是殘酷。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 메이슨 씨 일행도 저희 의뢰인을 찾아오신 모양이로군요.","JPN":"メイソンさんたちも僕たちの依頼主を探しに来られたようですね。","ENG":"It looks like you were looking for our client as well?","TWN":"不過梅森，你們也是要來找我們的委託人嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"맞아. 우리에겐 의뢰인이 아니라 작전 목표이긴 하지만.","JPN":"そうだ。俺たちにとっちゃ依頼主じゃなくて作戦のターゲットだがね。","ENG":"Yes. But for us, she’s our objective, not a client.","TWN":"沒錯，但她不是我們的委託人，而是我們的作戰目標。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호오……. 일이 참 공교롭게 얽힌 모양이네요.","JPN":"ほう……偶然にも複雑に絡み合ったようですね。","ENG":"Oh... It looks like things got tangled up.","TWN":"哇喔……還真是巧呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"상황이 상황이다 보니 자세히 설명하기엔 시간이 부족하군.","JPN":"状況が状況だからな。詳しい説明をする時間はない。","ENG":"Yes, but we don’t have time to explain.","TWN":"情況就是這樣，現在沒時間詳細說明。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"갑작스럽겠지만 제안 하나 하지. 우릴 도와 주지 않겠나?","JPN":"急だが一つ提案をしよう。我々を手伝ってくれないか？","ENG":"I have a suggestion. Will you help us?","TWN":"雖然有點突然，不過我有個提議，可以幫我們嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨를?","JPN":"おじさんを？","ENG":"Help you?","TWN":"幫大叔嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 이건 감일 뿐이지만 아무래도 아주 복잡한 일에 휘말린 것 같아.","JPN":"そうだ。これは単なる俺の勘だが、どうも面倒事に巻き込まれたようだ。","ENG":"Yes. I have a feeling that we got ourselves into a very complicated event.","TWN":"對，雖然這只是我的第六感，但總覺得捲入麻煩事了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"용병의 감은 함부로 무시해서는 안 되지.","JPN":"傭兵の勘を侮ってはいけないぞ。","ENG":"And a mercenary’s gut feeling is not something that should be easily ignored.","TWN":"不能小看傭兵的第六感！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이럴 때는 실력 좋고 믿을 수 있는 동료들이 필요해. 가능한 한 많이.","JPN":"こんな時は実力があって信頼できる仲間が必要だ。できる限りたくさんな。","ENG":"In a situation like this, you need competent, trustworthy friends. As many as possible.","TWN":"這種時候就需要能力好又值得信賴的夥伴，越多越好！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서 사태 때 같이 싸웠던 자네들이라면 자격이 충분하지.","JPN":"リプレイサー事件の時、共に戦ったお前たちならその資格が十分ある。","ENG":"Which would be you guys, who fought with me during the Replacer incident.","TWN":"你們就是非常適合的人選，畢竟我們曾經在克隆集團事件時一起並肩作戰過。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"의뢰비라면 걱정 마. 저 친구들이 넉넉하게 챙겨줄 거니까.","JPN":"依頼費なら心配するな。あの軍人さん方がたっぷり用意してくれるさ。","ENG":"Don’t worry about the money. Those military guys will take care of that.","TWN":"委託費的話不用擔心，那位哥絕對不會小氣的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 어떻게 할까요?","JPN":"ミナさん、どうしますか？","ENG":"Mina, what do you think?","TWN":"米娜，你說呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……좋아.","JPN":"……いいよ。","ENG":"... Okay.","TWN":"……好吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도 구원기사단과의 일이 이렇게 끝날 것 같지는 않아.","JPN":"私も救世騎士団との事がそんな簡単に終わるとは思えない。","ENG":"I feel like I have unfinished business with the Knights of Redemption.","TWN":"我也不認為和救贖騎士團的事會就這樣結束。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 소대장이나 부사장님은 물어봐도 대답해 주지 않을 거니까.","JPN":"でも、小隊長や副社長に聞いても教えてくれないから。","ENG":"But neither the Commander nor the Vice President will tell me what’s going on.","TWN":"可是就算我問小隊長或副總，他們什麼都不跟我說。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"샬롯이 왜 나를 노린 건지, 상대의 진짜 목표가 뭔지…….","JPN":"シャーロットがどうして私を狙ったのか、相手の本当の狙いは何か……","ENG":"Why Carlota attacked me, or what they actually want...","TWN":"夏洛特為什麼要對付我？對方真正的目的是什麼……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"직접 알아내야겠어.","JPN":"直接調べるしかないよ。","ENG":"I’m going to find out myself.","TWN":"我要親自找出答案來！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"좋은 생각입니다.","JPN":"いい考えですね。","ENG":"Good idea.","TWN":"很棒的想法。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇게 되었으니 잘 부탁드리죠, 메이슨 씨.","JPN":"ということなので、よろしくお願いします。メイソンさん。","ENG":"Well, we look forward to working with you, Mr. Mason.","TWN":"既然如此，那就請多指教囉，梅森。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 날 따라오라고, 전투는 이미 시작된 것 같으니까!","JPN":"じゃあ、しっかり俺に付いて来いよ！　戦闘はすでに始まってるからな！","ENG":"Then follow me. It looks like the battle has already begun!","TWN":"那跟我來吧，好像已經開戰了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};